import React from 'react';
import './Button.css';

function Button({ onAdd }) {
  const handleClick = () => {
    const text = prompt('Ingrese la nueva tarea');

    if (text && text.trim() !== '') {
      onAdd(text);
    }
  };

  return (
    <button
      className="CreateTodoButton"
      onClick={handleClick}
    >
      +
    </button>
  );
}

export { Button };
